import React, { useContext, useEffect } from 'react';
import { AppContext } from '../context/AppContext';

const ProfilePage = () => {
  const { user, orders, fetchOrders, deleteOrder } = useContext(AppContext);

  useEffect(() => {
    if (user) fetchOrders();
  }, [user]);

  if (!user) return <h2 style={{ padding: '20px' }}>Пожалуйста, войдите в систему</h2>;

  return (
    <div style={{ padding: '20px' }}>
      <h1>Личный кабинет: {user.username}</h1>
      <h3>Мои заказы:</h3>
      {orders.length === 0 ? <p>У вас пока нет заказов</p> : (
        <ul>
          {orders.map(order => (
            <li key={order.id} style={{ marginBottom: '15px' }}>
              Заказ №{order.id} от {order.date} — <strong>{order.total} KZT</strong>
              <button 
                onClick={() => deleteOrder(order.id)} 
                style={{ marginLeft: '15px', color: 'red' }}
              >
                Отменить (Delete)
              </button>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

export default ProfilePage;
